// ═══════════════════════════════════════════════════
// 计算本周时间范围
// ═══════════════════════════════════════════════════

const now = new Date();
const dayOfWeek = now.getDay();
const daysSinceSunday = dayOfWeek === 0 ? 7 : dayOfWeek;

const weekStart = new Date(now);
weekStart.setDate(now.getDate() - daysSinceSunday);
weekStart.setHours(0, 0, 0, 0);

const weekEnd = new Date(now);
weekEnd.setDate(now.getDate() - daysSinceSunday + 7);
weekEnd.setHours(0, 0, 0, 0);

return {
  weekStart: weekStart.toISOString(),
  weekEnd: weekEnd.toISOString(),
  weekLabel: `${weekStart.getMonth() + 1}/${weekStart.getDate()} - ${weekEnd.getMonth() + 1}/${weekEnd.getDate()}`,
  issueNumber: Math.floor((now.getTime() - new Date('2026-01-01').getTime()) / (7 * 86400000)),
  generatedAt: now.toISOString()
};

// ═══════════════════════════════════════════════════
// 构建周报 Prompt — 需要拉取本周帖子
// 通过 Next.js API 获取本周发布的所有文章
// ═══════════════════════════════════════════════════

const dates = $input.first().json;

const systemPrompt = `你是 Nexus Hub 的 「The Architect」，中枢调度官。你的任务是将本周所有 AI 生成的文章汇编成一份精美的学术周报。

## 周报风格
- 专业但不枯燥，像一位有品位的编辑在为你精选本周必读
- 开头用一段温暖的引语（50字内）
- 每篇文章摘要 80-120 字，突出核心发现
- 结尾加一句下周预告

## 格式要求
- 使用 HTML 邮件格式（适配 EDM 发送）
- 内联 CSS 样式
- 移动端友好的响应式布局
- 包含 Nexus Hub 品牌色 (#f97316 橙色为主色调)

## 输出格式
直接输出完整 HTML 邮件代码，从 <!DOCTYPE html> 开始`;

const userPrompt = `请根据以下本周发布的文章，生成第 ${dates.issueNumber} 期 Nexus Hub 学术周报。

本周范围: ${dates.weekLabel}

## 本周文章
{{WEEKLY_POSTS}}

请生成一份精美的 HTML 邮件周报。`;

return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 4096,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  _weekLabel: dates.weekLabel,
  _issueNumber: dates.issueNumber
};

// ═══════════════════════════════════════════════════
// 将本周文章注入 Prompt 模板
// ═══════════════════════════════════════════════════

const apiResponse = $input.first().json;
const posts = apiResponse.posts || [];
const prev = $('📝 构建周报 Prompt').first().json;

// 格式化文章列表
const postsText = posts.length > 0
  ? posts.map((p, i) => `${i + 1}. **${p.title}** [${p.subreddit}]\n   ${(p.summary || p.content || '').substring(0, 300)}`).join('\n\n')
  : '(本周暂无 AI 生成的文章 — 请 Owl 抓取更多资讯源)';

// 注入到 user message 中
const userMessage = prev.messages[1].content.replace('{{WEEKLY_POSTS}}', postsText);

return {
  model: prev.model,
  temperature: prev.temperature,
  max_tokens: prev.max_tokens,
  messages: [
    prev.messages[0],
    { role: 'user', content: userMessage }
  ],
  _weekLabel: prev._weekLabel,
  _issueNumber: prev._issueNumber,
  _postCount: posts.length
};

// ═══════════════════════════════════════════════════
// 提取 HTML 邮件内容
// ═══════════════════════════════════════════════════

const response = $input.first().json;
const prev = $('🔧 注入文章数据').first().json;

const htmlContent = response.choices?.[0]?.message?.content || '';

// 提取 HTML 部分（去掉可能的 markdown 包裹）
const htmlMatch = htmlContent.match(/<!DOCTYPE[\s\S]*<\/html>/i);
const html = htmlMatch ? htmlMatch[0] : htmlContent;

return {
  subject: `📬 Nexus Hub 学术周报 #${prev._issueNumber} — ${prev._weekLabel}`,
  html: html,
  _weekLabel: prev._weekLabel,
  _issueNumber: prev._issueNumber,
  _postCount: prev._postCount
};

// ═══════════════════════════════════════════════════
// 周报发送完成
// ═══════════════════════════════════════════════════

const result = $input.first().json;
const prev = $('📧 提取邮件 HTML').first().json;

return {
  pipeline: 'architect-newsletter',
  status: result.id ? 'sent' : 'api_response',
  issue: prev._issueNumber,
  week: prev._weekLabel,
  postsIncluded: prev._postCount,
  resendId: result.id || 'N/A',
  timestamp: new Date().toISOString()
};
